class Solution:
    def isSubsequence(self, nums1: list[int], nums2: list[int]) -> bool:
        m, n = len(nums1), len(nums2)
        i = 0
        for j in range(m):
            while i < n and nums1[j] != nums2[i]:
                i += 1
            if i == n:
                return False
            i += 1
        return True

    def main(self):
        n, m = map(int, input().split())
        nums1 = list(map(int, input().split()))
        nums2 = list(map(int, input().split()))
        print('Yes' if self.isSubsequence(nums1, nums2) else 'No')

